spec.query:
from(bucket: "server_metrics")
  |> range(start: -5m)
  |> filter(fn: (r) => r._measurement == "cpu")
  |> filter(fn: (r) => r.cpu == "cpu-total")
  |> filter(fn: (r) => r._field == "usage_idle")
  |> last()
  |> map(fn: (r) => ({
      _value: 100.0 - r._value
  }))

from(bucket: "server_metrics")
  |> range(start: -5m)
  |> filter(fn: (r) => r._measurement == "procstat")
